using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Zona de respawn de inimigos (Etapa 7.3): um Collider2D (trigger) que cobre
/// uma área do nível. Quando o player SAI e volta a ENTRAR na zona, todos os
/// inimigos com EnemyRespawn cuja HomePosition está dentro da zona fazem
/// <see cref="EnemyRespawn.TryRespawn"/>:
///
/// - Comuns voltam (vida/drops comuns/posição/estado);
/// - Especiais e mini-bosses derrotados permanecem mortos (registo no
///   PlayerProgress);
/// - Desactivados por variável global voltam a desactivar-se de imediato
///   (a condição da Etapa 5.4 continua verdadeira).
///
/// Enquanto o player permanecer dentro da zona, nada respawna.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class EnemyRespawnZone : MonoBehaviour
{
    [Tooltip("Se activo, o respawn acontece na reentrada do player na zona (padrão). Desliga para zonas controladas manualmente via RespawnAll().")]
    public bool respawnOnPlayerReenter = true;

    private Collider2D _collider;
    private bool _playerInside;
    private bool _playerLeftOnce;

    // Snapshot reutilizável — evita ToArray() (alocação) em RespawnAll().
    private readonly List<EnemyRespawn> _respawnSnapshot = new List<EnemyRespawn>();

    private void Awake()
    {
        _collider = GetComponent<Collider2D>();

        if (!_collider.isTrigger)
            Debug.LogWarning($"[{name}] O Collider2D da EnemyRespawnZone deve ser 'Is Trigger'.", this);
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        // Guard: se já está marcado como dentro (múltiplos colliders no player
        // com tag "Player"), ignorar entradas duplicadas no mesmo frame.
        if (_playerInside) return;

        bool reentering = _playerLeftOnce;
        _playerInside = true;

        if (reentering && respawnOnPlayerReenter)
            RespawnAll();
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        _playerInside = false;
        _playerLeftOnce = true;
    }

    /// <summary>Respawna todos os inimigos (EnemyRespawn) cuja HomePosition está dentro desta zona. Também chamável manualmente (eventos/checkpoints).</summary>
    public void RespawnAll()
    {
        var bounds = _collider.bounds;

        // Itera uma cópia: TryRespawn pode activar/desactivar GameObjects (altera EnemyRespawn.All).
        _respawnSnapshot.Clear();
        _respawnSnapshot.AddRange(EnemyRespawn.All);
        var snapshot = _respawnSnapshot;

        foreach (var respawn in snapshot)
        {
            if (respawn == null) continue;

            var controller = respawn.GetComponent<EnemyController>();
            Vector3 home = controller != null ? controller.HomePosition : respawn.transform.position;

            if (bounds.Contains(new Vector3(home.x, home.y, bounds.center.z)))
                respawn.TryRespawn();
        }
    }
}
